  1→using System;
  2→using System.Collections.Generic;
  3→
  4→namespace WeldMonitor3
  5→{
  6→    /// <summary>
  7→    /// PLC 블록 정보 (시작번지, 개수)
  8→    /// </summary>
  9→    public class PlcBlock
 10→    {
 11→        public int StartAddress { get; set; }
 12→        public int Count { get; set; }
 13→
 14→        public PlcBlock(int start, int count)
 15→        {
 16→            StartAddress = start;
 17→            Count = count;
 18→        }
