 21→    /// <summary>
 22→    /// MELSEC PLC 통신 헬퍼 (AxACTETHERLib ActiveX 사용 - pop_single과 동일)
 23→    /// </summary>
 24→    public class MelsecHelper : IDisposable
 25→    {
 26→        // ActiveX 컨트롤 (AxACTETHERLib.AxActQNUDECPUTCP)
 27→        private AxACTETHERLib.AxActQNUDECPUTCP _actPlc;
 28→        private bool _isConnected;
 29→        private bool _isDisposed;
 30→        private readonly object _lock = new object();  // 동시 접근 방지
 31→
 32→        // CPU 타입 (Q Series = 209)
 33→        private const int PLC_CPU_TYPE = 209;
 34→
 35→        /// <summary>
 36→        /// PLC 연결 상태
 37→        /// </summary>
 38→        public bool IsConnected => _isConnected;
 39→
 40→        /// <summary>
 41→        /// 마지막 에러 메시지
 42→        /// </summary>
 43→        public string LastError { get; private set; }
 44→
 45→        /// <summary>
 46→        /// 읽은 PLC 값 저장 배열 (IoInput[번지] = 값)
 47→        /// </summary>
 48→        public int[] IoInput { get; private set; } = new int[10000];
 49→
 50→        /// <summary>
 51→        /// 생성자 - ActiveX 컨트롤을 외부에서 전달받음
 52→        /// </summary>
 53→        public MelsecHelper(AxACTETHERLib.AxActQNUDECPUTCP actPlc)
 54→        {
 55→            _actPlc = actPlc;
 56→            if (_actPlc != null)
 57→            {
 58→                Logger.Log("[PLC] ActiveX 컨트롤 전달받음");
 59→            }
 60→            else
 61→            {
 62→                Logger.Error("[PLC] ActiveX 컨트롤이 null입니다");
 63→            }
 64→        }
 65→
 66→        /// <summary>
 67→        /// PLC 연결
 68→        /// </summary>
 69→        /// <returns>성공 여부</returns>
 70→        public bool Connect()
 71→        {
 72→            string plcIp = GlobalValues.plcIpAddress ?? "192.168.0.1";
 73→            Logger.Log($"[PLC] 연결 시도 - IP: {plcIp}, CPU Type: {PLC_CPU_TYPE}");
 74→
 75→            try
 76→            {
 77→                if (_actPlc == null)
 78→                {
 79→                    LastError = "ActiveX 컨트롤이 초기화되지 않았습니다.";
 80→                    Logger.Error($"[PLC] {LastError}");
 81→                    _isConnected = false;
 82→                    return false;
 83→                }
 84→
 85→                // 재접속 시 기존 연결 먼저 닫기
 86→                try
 87→                {
 88→                    _actPlc.Close();
 89→                }
 90→                catch { }  // Close 실패해도 무시 (이미 닫혀있을 수 있음)
 91→
 92→                // CPU 타입/IP 설정
 93→                _actPlc.ActCpuType = PLC_CPU_TYPE;
 94→                _actPlc.ActHostAddress = plcIp;
 95→                _actPlc.ActTimeOut = 1000;
 96→
 97→                // 연결
 98→                int result = _actPlc.Open();
 99→                if (result != 0)
100→                {
101→                    LastError = $"PLC 연결 실패 (0x{result:X8})";
102→                    Logger.Error($"[PLC] {LastError}");
103→                    _isConnected = false;
104→                    return false;
105→                }
106→
107→                _isConnected = true;
108→                LastError = "OK";
109→                Logger.Log("[PLC] 연결 성공!");
110→                return true;
111→            }
112→            catch (Exception ex)
113→            {
114→                LastError = ex.Message;
115→                _isConnected = false;
116→                Logger.Error($"[PLC] 연결 예외 발생: {ex.Message}");
117→                return false;
118→            }
119→        }
120→
121→        /// <summary>
122→        /// PLC 연결 해제
123→        /// </summary>
124→        public void Disconnect()
125→        {
126→            Logger.Log("[PLC] 연결 해제 시도...");
127→            try
128→            {
129→                if (_actPlc != null && _isConnected)
130→                {
131→                    _actPlc.Close();
132→                    Logger.Log("[PLC] 연결 해제 완료");
133→                }
134→            }
135→            catch (Exception ex)
136→            {
137→                Logger.Error($"[PLC] 연결 해제 예외: {ex.Message}");
138→            }
139→            finally
140→            {
141→                _isConnected = false;
142→            }
143→        }
144→
145→        /// <summary>
146→        /// MELSEC PLC 읽기 (W 레지스터 사용, pop_single과 동일)
147→        /// </summary>
148→        public bool ReadPlcMelsec(int startInAddress, int inDataNumber, int startOutAddress, int outDataNumber)
149→        {
150→            if (!_isConnected || _actPlc == null)
151→            {
152→                LastError = "연결 안됨";
153→                return false;
154→            }
155→
156→            int arraySize = inDataNumber + outDataNumber;
157→            short[] deviceValues = new short[arraySize];
158→            string deviceName = "";
159→
160→            // 입력 번지 문자열 생성
161→            for (int i = 0; i < inDataNumber; i++)
162→            {
163→                deviceName += "W" + (startInAddress + i).ToString() + "\n";
164→            }
165→
166→            // 출력 번지 문자열 생성
167→            for (int i = 0; i < outDataNumber; i++)
168→            {
169→                if (i == outDataNumber - 1)
170→                    deviceName += "W" + (startOutAddress + i).ToString();
171→                else
172→                    deviceName += "W" + (startOutAddress + i).ToString() + "\n";
173→            }
174→
175→            try
176→            {
177→                int returnCode = _actPlc.ReadDeviceRandom2(deviceName, arraySize, out deviceValues[0]);
178→
179→                if (returnCode == 0)
180→                {
181→                    // 입력 값 저장
182→                    for (int i = 0; i < inDataNumber; i++)
183→                    {
184→                        IoInput[i + startInAddress] = deviceValues[i];
185→                    }
186→                    // 출력 값 저장
187→                    for (int i = 0; i < outDataNumber; i++)
188→                    {
189→                        IoInput[i + startOutAddress] = deviceValues[i + inDataNumber];
190→                    }
191→                    LastError = "OK";
192→                    return true;
193→                }
194→                else
195→                {
196→                    LastError = $"0x{returnCode:X8}";
197→                    Logger.Error($"[PLC] ReadPlcMelsec 에러: {LastError}");
198→                    return false;
199→                }
200→            }
201→            catch (Exception ex)
202→            {
203→                LastError = ex.Message;
204→                Logger.Error($"[PLC] ReadPlcMelsec 예외: {ex.Message}");
205→                _isConnected = false;
206→                return false;
207→            }
208→        }
209→
210→        /// <summary>
211→        /// MELSEC PLC 쓰기 (pop_single과 동일)
212→        /// </summary>
213→        public bool WritePlcMelsec(string deviceType, string startAddress, string message)
214→        {
215→            if (!_isConnected || _actPlc == null)
216→            {
217→                LastError = "연결 안됨";
218→                return false;
219→            }
220→
221→            if (LastError != "OK")
222→            {
223→                return false;
224→            }
225→
226→            short[] deviceValues = new short[message.Length];
227→            string deviceName = "";
228→
229→            for (int i = 0; i < message.Length; i++)
230→            {
231→                deviceName += deviceType + (int.Parse(startAddress) + i).ToString("00000");
232→                if (i < message.Length - 1)
233→                    deviceName += "\n";
234→                deviceValues[i] = short.Parse(message.Substring(i, 1));
235→            }
236→
237→            try
238→            {
239→                int returnCode = _actPlc.WriteDeviceRandom2(deviceName, message.Length, ref deviceValues[0]);
240→
241→                if (returnCode != 0)
242→                {
243→                    Logger.Error($"[PLC] WritePlcMelsec 에러: 0x{returnCode:X8}");
244→                    return false;
245→                }
246→                return true;
247→            }
248→            catch (Exception ex)
249→            {
250→                Logger.Error($"[PLC] WritePlcMelsec 예외: {ex.Message}");
251→                _isConnected = false;
252→                return false;
253→            }
254→        }
255→
256→        /// <summary>
257→        /// D 레지스터 1개 읽기
258→        /// </summary>
259→        public int ReadD(int address)
260→        {
261→            if (!_isConnected || _actPlc == null)
262→            {
263→                return 0;
264→            }
265→
266→            lock (_lock)
267→            {
268→                try
269→                {
270→                    short[] values = new short[1];
271→                    string deviceName = $"D{address}";
272→                    int returnCode = _actPlc.ReadDeviceRandom2(deviceName, 1, out values[0]);
273→
274→                    if (returnCode == 0)
275→                    {
276→                        return values[0];
277→                    }
278→                    return 0;
279→                }
280→                catch
281→                {
282→                    return 0;
283→                }
284→            }
285→        }
286→
287→        /// <summary>
288→        /// D 레지스터 1개 쓰기
289→        /// </summary>
290→        public bool WriteD(int address, int value)
291→        {
292→            if (!_isConnected || _actPlc == null)
293→            {
294→                return false;
295→            }
296→
297→            lock (_lock)
298→            {
299→                try
300→                {
301→                    short[] values = new short[] { (short)value };
302→                    string deviceName = $"D{address}";
303→                    int returnCode = _actPlc.WriteDeviceRandom2(deviceName, 1, ref values[0]);
304→                    return returnCode == 0;
305→                }
306→                catch
307→                {
308→                    return false;
309→                }
310→            }
311→        }
312→
313→        /// <summary>
314→        /// D 레지스터 블록 읽기
315→        /// </summary>
316→        public int[] ReadDBlock(int startAddress, int count)
317→        {
318→            if (!_isConnected || _actPlc == null)
319→            {
320→                return null;
321→            }
322→
323→            try
324→            {
325→                short[] buffer = new short[count];
326→                string deviceName = "";
327→
328→                for (int i = 0; i < count; i++)
329→                {
330→                    if (i == count - 1)
331→                        deviceName += $"D{startAddress + i}";
332→                    else
333→                        deviceName += $"D{startAddress + i}\n";
334→                }
335→
336→                int returnCode = _actPlc.ReadDeviceRandom2(deviceName, count, out buffer[0]);
337→
338→                if (returnCode == 0)
339→                {
340→                    int[] result = new int[count];
341→                    for (int i = 0; i < count; i++)
342→                        result[i] = buffer[i];
343→                    return result;
344→                }
345→                return null;
346→            }
347→            catch
348→            {
349→                return null;
350→            }
351→        }
352→
353→        /// <summary>
354→        /// D 레지스터 블록 쓰기
355→        /// </summary>
356→        public bool WriteDBlock(int startAddress, int[] values)
357→        {
358→            if (!_isConnected || _actPlc == null || values == null || values.Length == 0)
359→            {
360→                return false;
361→            }
362→
363→            try
364→            {
365→                short[] buffer = new short[values.Length];
366→                string deviceName = "";
367→
368→                for (int i = 0; i < values.Length; i++)
369→                {
370→                    if (i == values.Length - 1)
371→                        deviceName += $"D{startAddress + i}";
372→                    else
373→                        deviceName += $"D{startAddress + i}\n";
374→                    buffer[i] = (short)values[i];
375→                }
376→
377→                int returnCode = _actPlc.WriteDeviceRandom2(deviceName, values.Length, ref buffer[0]);
378→                return returnCode == 0;
379→            }
380→            catch
381→            {
382→                return false;
383→            }
384→        }
385→
386→        public void Dispose()
387→        {
388→            if (!_isDisposed)
389→            {
390→                Disconnect();
391→                // ActiveX 컨트롤은 폼에서 관리하므로 여기서 해제하지 않음
392→                _actPlc = null;
393→                _isDisposed = true;
394→            }
395→        }
396→
397→        #region 유틸리티 메서드
398→
399→        /// <summary>
400→        /// 블록 문자열 파싱 ("4008_12 / 4200_5" → List of PlcBlock)
401→        /// </summary>
402→        public static List<PlcBlock> ParseBlocks(string blockString)
403→        {
404→            var blocks = new List<PlcBlock>();
405→            if (string.IsNullOrWhiteSpace(blockString))
406→                return blocks;
407→
408→            string[] parts = blockString.Split(new[] { " / ", "/" }, StringSplitOptions.RemoveEmptyEntries);
409→            foreach (string part in parts)
410→            {
411→                string trimmed = part.Trim();
412→                int underscoreIdx = trimmed.IndexOf('_');
413→                if (underscoreIdx > 0)
414→                {
415→                    string startStr = trimmed.Substring(0, underscoreIdx);
416→                    string countStr = trimmed.Substring(underscoreIdx + 1);
417→                    if (int.TryParse(startStr, out int start) && int.TryParse(countStr, out int count))
418→                    {
419→                        if (start >= 0 && count > 0)
420→                        {
421→                            blocks.Add(new PlcBlock(start, count));
422→                        }
423→                    }
424→                }
425→            }
426→            return blocks;
427→        }
428→
429→        /// <summary>
430→        /// 여러 블록을 ReadDeviceRandom2로 한 번에 읽기
431→        /// </summary>
432→        public Dictionary<int, int> ReadMultipleBlocks(List<PlcBlock> blocks)
433→        {
434→            var result = new Dictionary<int, int>();
435→            if (!_isConnected || _actPlc == null || blocks == null || blocks.Count == 0)
436→            {
437→                return result;
438→            }
439→
440→            lock (_lock)
441→            {
442→                try
443→                {
444→                    var addressList = new List<int>();
445→                    foreach (var block in blocks)
446→                    {
447→                        for (int i = 0; i < block.Count; i++)
448→                        {
449→                            addressList.Add(block.StartAddress + i);
450→                        }
451→                    }
452→
453→                    if (addressList.Count == 0)
454→                        return result;
455→
456→                    var deviceNames = new System.Text.StringBuilder();
457→                    for (int i = 0; i < addressList.Count; i++)
458→                    {
459→                        deviceNames.Append($"D{addressList[i]}");
460→                        if (i < addressList.Count - 1)
461→                            deviceNames.Append("\n");
462→                    }
463→
464→                    short[] buffer = new short[addressList.Count];
465→                    int returnCode = _actPlc.ReadDeviceRandom2(deviceNames.ToString(), addressList.Count, out buffer[0]);
466→
467→                    if (returnCode == 0)
468→                    {
469→                        for (int i = 0; i < addressList.Count; i++)
470→                        {
471→                            result[addressList[i]] = buffer[i];
472→                        }
473→                        LastError = "OK";
474→                    }
475→                    else
476→                    {
477→                        LastError = $"0x{returnCode:X8}";
478→                        _isConnected = false;  // 읽기 실패 시 연결 끊김으로 간주
479→                        Logger.Error($"[PLC] ReadMultipleBlocks 실패: {LastError}");
480→                    }
481→                }
482→                catch (Exception ex)
483→                {
484→                    LastError = ex.Message;
485→                    _isConnected = false;  // 예외 발생 시 연결 끊김으로 간주
486→                    Logger.Error($"[PLC] ReadMultipleBlocks 예외: {ex.Message}");
487→                }
488→            }
489→
490→            return result;
491→        }
492→
493→        /// <summary>
494→        /// 블록 문자열로 여러 블록 읽기
495→        /// </summary>
496→        public Dictionary<int, int> ReadBlocksFromString(string blockString)
497→        {
498→            var blocks = ParseBlocks(blockString);
499→            return ReadMultipleBlocks(blocks);
500→        }
501→
502→        /// <summary>
503→        /// 특정 번지가 블록 범위 내에 있는지 확인
504→        /// </summary>
505→        public static bool IsAddressInBlocks(int address, List<PlcBlock> blocks)
506→        {
507→            foreach (var block in blocks)
508→            {
509→                if (address >= block.StartAddress && address < block.StartAddress + block.Count)
510→                    return true;
511→            }
512→            return false;
513→        }
514→
515→        /// <summary>
516→        /// 특정 번지가 블록 문자열 범위 내에 있는지 확인
517→        /// </summary>
518→        public static bool IsAddressInBlockString(int address, string blockString)
519→        {
520→            var blocks = ParseBlocks(blockString);
521→            return IsAddressInBlocks(address, blocks);
522→        }
523→
524→        #endregion
525→    }
526→}
