124→        /// <summary>
125→        /// PropertyGrid의 Help(설명) 영역 높이를 조정합니다.
126→        /// </summary>
127→        private void AdjustPropertyGridHelpHeight(PropertyGrid grid, int height)
128→        {
129→            try
130→            {
131→                var type = grid.GetType();
132→                bool found = false;
133→                System.Text.StringBuilder debug = new System.Text.StringBuilder();
134→                debug.AppendLine($"PropertyGrid Total Height: {grid.Height}");
135→                debug.AppendLine("PropertyGrid Controls:");
136→
137→                // 모든 컨트롤 확인 (디버깅)
138→                foreach (Control control in grid.Controls)
139→                {
140→                    debug.AppendLine($"  {control.GetType().Name}: H={control.Height}, Visible={control.Visible}, Dock={control.Dock}");
141→                }
142→
143→                // 방법 1: Controls 컬렉션에서 DocComment와 PropertyGridView 찾기
144→                Control docComment = null;
145→                Control gridView = null;
146→                Control toolStrip = null;
147→
148→                foreach (Control control in grid.Controls)
149→                {
150→                    string typeName = control.GetType().Name;
151→                    if (typeName == "DocComment")
152→                        docComment = control;
153→                    else if (typeName == "PropertyGridView")
154→                        gridView = control;
155→                    else if (typeName == "PropertyGridToolStrip")
156→                        toolStrip = control;
157→                }
158→
159→                if (docComment != null && gridView != null)
160→                {
161→                    int toolStripHeight = toolStrip != null ? toolStrip.Height : 0;
162→                    int totalHeight = grid.ClientSize.Height - toolStripHeight;
163→                    int newGridViewHeight = totalHeight - height;
164→
165→                    int oldDocHeight = docComment.Height;
166→                    int oldGridViewHeight = gridView.Height;
167→
168→                    // GridView와 DocComment 높이 동시 조정
169→                    gridView.Height = newGridViewHeight;
170→                    docComment.Height = height;
171→                    docComment.Top = gridView.Bottom;
172→
173→                    debug.AppendLine($"\n✓ PropertyGridView: {oldGridViewHeight} → {newGridViewHeight}");
174→                    debug.AppendLine($"✓ DocComment: {oldDocHeight} → {height}");
175→                    found = true;
176→                }
177→
178→                // 방법 2: 리플렉션으로 필드 직접 접근 (방법 1이 실패한 경우)
179→                if (!found)
180→                {
181→                    var docCommentField = type.GetField("doccomment",
182→                        System.Reflection.BindingFlags.NonPublic |
183→                        System.Reflection.BindingFlags.Instance);
184→
185→                    if (docCommentField != null)
186→                    {
187→                        docComment = docCommentField.GetValue(grid) as Control;
188→                        if (docComment != null)
189→                        {
190→                            int oldHeight = docComment.Height;
191→                            docComment.Height = height;
192→                            debug.AppendLine($"\n✓ DocComment field height changed: {oldHeight} → {height}");
193→                            found = true;
194→                        }
195→                    }
196→                    else
197→                    {
198→                        debug.AppendLine("\n✗ doccomment field not found");
199→                    }
200→                }
201→
202→                // 방법 3: MoveSplitter 메서드 시도
203→                var moveSplitterMethod = type.GetMethod("MoveSplitter",
204→                    System.Reflection.BindingFlags.NonPublic |
205→                    System.Reflection.BindingFlags.Instance);
206→
207→                if (moveSplitterMethod != null)
208→                {
209→                    debug.AppendLine($"\n✓ Trying MoveSplitter with offset: {-height}");
210→                    moveSplitterMethod.Invoke(grid, new object[] { -height });
211→                }
212→
213→                grid.Refresh();
214→                System.Diagnostics.Debug.WriteLine(debug.ToString());
215→
216→                // 정보 메시지박스 (한번만 표시)
217→                //MessageBox.Show(debug.ToString(), "PropertyGrid Debug", MessageBoxButtons.OK, MessageBoxIcon.Information);
218→            }
219→            catch (Exception ex)
220→            {
221→                MessageBox.Show(this, LanguageManager.Get("msg_config_error", ex.Message, ex.StackTrace), LanguageManager.Get("msg_error"), MessageBoxButtons.OK, MessageBoxIcon.Error);
222→            }
223→        }
224→    }
