177→        // 실행 파일이 C:\Program Files에 있어도 읽기만 하므로 관리자 권한 불필요
178→        private static void InitializeDatabase(string dbFileName)
179→        {
180→            string userDbPath = Path.Combine(GetDbPath(), dbFileName);
181→
182→            // 사용자 DB가 이미 있으면 복사 불필요
183→            if (File.Exists(userDbPath))
184→            {
185→                return;
186→            }
187→
188→            // 설치 폴더에서 기본 DB 찾기 (여러 위치 시도)
189→            string[] possiblePaths = new[]
190→            {
191→                Path.Combine(AppDomain.CurrentDomain.BaseDirectory, "DefaultData", "DB", dbFileName),  // 설치본
192→                Path.Combine(AppDomain.CurrentDomain.BaseDirectory, "DB", dbFileName),  // 개발환경
193→                Path.Combine(Path.GetDirectoryName(System.Reflection.Assembly.GetExecutingAssembly().Location), "DB", dbFileName)
194→            };
195→
196→            foreach (string defaultDbPath in possiblePaths)
197→            {
198→                if (File.Exists(defaultDbPath))
199→                {
200→                    try
201→                    {
202→                        File.Copy(defaultDbPath, userDbPath, false);
203→                        System.Diagnostics.Debug.WriteLine($"DB 초기화 성공: {dbFileName} -> {userDbPath}");
204→                        return;
205→                    }
206→                    catch (Exception ex)
207→                    {
208→                        System.Diagnostics.Debug.WriteLine($"DB 복사 실패: {ex.Message}");
209→                        // 다음 경로 시도
210→                    }
211→                }
212→            }
213→
214→            // .mdb 파일이 없으면 기존 .accdb에서 데이터 마이그레이션 시도
215→            string accdbFileName = dbFileName.Replace(".mdb", ".accdb");
216→            string[] accdbPaths = new[]
217→            {
218→                Path.Combine(GetDbPath(), accdbFileName),  // 사용자 폴더의 기존 accdb
219→                Path.Combine(AppDomain.CurrentDomain.BaseDirectory, "DefaultData", "DB", accdbFileName),
220→                Path.Combine(AppDomain.CurrentDomain.BaseDirectory, "DB", accdbFileName)
221→            };
222→
223→            foreach (string accdbPath in accdbPaths)
224→            {
225→                if (File.Exists(accdbPath))
226→                {
227→                    System.Diagnostics.Debug.WriteLine($"기존 .accdb 발견, .mdb로 변환 시도: {accdbPath}");
228→                    // .accdb에서 .mdb로 직접 변환은 불가, 새 .mdb 생성 후 데이터 복사 필요
229→                    // 여기서는 새 .mdb 생성만 진행
230→                    break;
231→                }
232→            }
233→
234→            // 기본 DB가 없으면 새로 생성 (ADOX 사용)
235→            System.Diagnostics.Debug.WriteLine($"DB 파일 새로 생성: {userDbPath}");
236→            CreateNewMdbDatabase(userDbPath, dbFileName);
237→        }
