448→            // 새 DB 경로와 동일하면 스킵
449→            string newDbPath = Path.Combine(GetDbPath(), "DataBase_Part.mdb");
450→            if (Path.GetFullPath(legacyDbPath).Equals(Path.GetFullPath(newDbPath), StringComparison.OrdinalIgnoreCase))
