468→                {
469→                    legacyConn.Open();
470→                    newConn.Open();
471→
472→                    // 1. 새 DB의 기존 Jig_ID 목록 가져오기
473→                    var existingJigIds = new HashSet<string>();
474→                    using (var cmd = new OleDbCommand("SELECT Jig_ID FROM Table_Jig", newConn))
