480→                        }
481→                    }
482→
483→                    // 2. 레거시 DB에서 Table_Jig 읽기
484→                    var legacyJigs = new DataTable();
485→                    using (var adapter = new OleDbDataAdapter("SELECT * FROM Table_Jig", legacyConn))
486→                    {
487→                        adapter.Fill(legacyJigs);
488→                    }
489→
490→                    // 3. 레거시 DB에서 Table_Seq 읽기
491→                    var legacySeqs = new DataTable();
492→                    using (var adapter = new OleDbDataAdapter("SELECT * FROM Table_Seq", legacyConn))
