533→                                cmd.Parameters.AddWithValue("?", seqRow["Value2_Max"] ?? 0);
534→                                cmd.Parameters.AddWithValue("?", seqRow["Value2_Min"] ?? 0);
535→                                cmd.Parameters.AddWithValue("?", seqRow["Value3_Max"] ?? 0);
536→                                cmd.Parameters.AddWithValue("?", seqRow["Value3_Min"] ?? 0);
537→                                cmd.Parameters.AddWithValue("?", seqRow["Value1_Tol"] ?? 1);
538→                                cmd.Parameters.AddWithValue("?", seqRow["Value2_Tol"] ?? 1);
539→                                cmd.Parameters.AddWithValue("?", seqRow["Value3_Tol"] ?? 1);
540→                                cmd.Parameters.AddWithValue("?", seqRow["Value1_Type"] ?? "Average");
541→                                cmd.Parameters.AddWithValue("?", seqRow["Value2_Type"] ?? "Average");
542→                                cmd.Parameters.AddWithValue("?", seqRow["Value3_Type"] ?? "Average");
543→                                cmd.Parameters.AddWithValue("?", seqRow["StartSector"] ?? 5);
