575→        private static string FindLegacyDatabase()
576→        {
577→            // 마이그레이션 완료 플래그 확인
578→            string migrationFlagPath = Path.Combine(GetDbPath(), ".migration_done");
579→            if (File.Exists(migrationFlagPath))
580→            {
581→                System.Diagnostics.Debug.WriteLine("이미 마이그레이션 완료됨");
582→                return null;
583→            }
584→
585→            // 검색할 Program Files 경로
586→            var programFilesPaths = new List<string>();
587→
588→            foreach (var drive in DriveInfo.GetDrives())
589→            {
590→                if (drive.DriveType != DriveType.Fixed) continue;
591→
592→                string root = drive.Name;
593→                programFilesPaths.Add(Path.Combine(root, "Program Files"));
594→                programFilesPaths.Add(Path.Combine(root, "Program Files (x86)"));
595→            }
596→
597→            // Program Files에서 "ftech"로 시작하는 폴더 검색
598→            foreach (string programFiles in programFilesPaths)
599→            {
600→                if (!Directory.Exists(programFiles)) continue;
601→
602→                try
603→                {
604→                    var ftechFolders = Directory.GetDirectories(programFiles, "ftech*", SearchOption.TopDirectoryOnly);
605→                    foreach (string ftechFolder in ftechFolders)
606→                    {
607→                        string dbPath = Path.Combine(ftechFolder, "DB", "DataBase_Part.mdb");
608→                        if (File.Exists(dbPath))
609→                        {
610→                            return dbPath;
611→                        }
612→                    }
613→                }
614→                catch (UnauthorizedAccessException)
615→                {
616→                    // 권한 없는 폴더 무시
617→                }
618→            }
619→
620→            // 현재 실행 파일 경로의 DB 폴더도 확인
621→            string localDbPath = Path.Combine(AppDomain.CurrentDomain.BaseDirectory, "DB", "DataBase_Part.mdb");
622→            if (File.Exists(localDbPath))
623→            {
624→                return localDbPath;
625→            }
626→
627→            return null;
628→        }
