774→        public static double TryGetDouble(IniFile ini, string section, string key, double defaultValue = 0.0)
775→        {
776→            string valueStr = ini.ReadValue(section, key);
777→
778→            if (string.IsNullOrWhiteSpace(valueStr))
779→            {
780→                // 값이 없으면 기본값 0 저장
781→                ini.WriteValue(section, key, "0");
782→                return 0.0;
783→            }
784→
785→            if (double.TryParse(valueStr, out double result))
786→            {
787→                return result;
788→            }
789→
790→            // 숫자 변환 실패 시도 → 0으로 저장
791→            //Console.WriteLine($"[INI 경고] {section}:{key} = '{valueStr}' → 숫자 변환 실패, 기본값 0 저장");
792→            ini.WriteValue(section, key, "0");
793→            return 0.0;
794→        }
795→        public static int TryGetInt(IniFile ini, string section, string key, int defaultValue = 0)
796→        {
797→            string valueStr = ini.ReadValue(section, key);
798→
799→            if (string.IsNullOrWhiteSpace(valueStr))
800→            {
801→                // 값이 없으면 기본값 저장
802→                ini.WriteValue(section, key, defaultValue.ToString());
803→                return defaultValue;
804→            }
805→
806→            if (int.TryParse(valueStr, out int result))
807→            {
808→                return result;
809→            }
810→
811→            // 숫자 변환 실패 → 기본값으로 저장
812→            ini.WriteValue(section, key, defaultValue.ToString());
813→            return defaultValue;
814→        }
815→        public static void LoadSettingsFromIni()
816→        {
817→            string newConfigPath = GetConfigPath();
818→
819→            // 사용자 폴더에 config.ini가 없으면 설치 폴더에서 복사
820→            if (!File.Exists(newConfigPath))
821→            {
822→                // 여러 위치에서 기본 config.ini 찾기
823→                string[] possiblePaths = new[]
824→                {
825→                    Path.Combine(AppDomain.CurrentDomain.BaseDirectory, "DefaultData", "config.ini"),  // 설치본
826→                    Path.Combine(AppDomain.CurrentDomain.BaseDirectory, "config.ini")  // 개발환경/기존
827→                };
828→
829→                foreach (string srcPath in possiblePaths)
830→                {
831→                    if (File.Exists(srcPath))
832→                    {
833→                        try
834→                        {
835→                            // 사용자 폴더 생성
836→                            string userDir = Path.GetDirectoryName(newConfigPath);
837→                            if (!Directory.Exists(userDir))
838→                                Directory.CreateDirectory(userDir);
839→
840→                            File.Copy(srcPath, newConfigPath, false);
841→                            System.Diagnostics.Debug.WriteLine($"Config 초기화 성공: {srcPath} -> {newConfigPath}");
842→                            break;
843→                        }
844→                        catch (Exception ex)
845→                        {
846→                            System.Diagnostics.Debug.WriteLine($"Config 복사 실패: {ex.Message}");
847→                        }
848→                    }
849→                }
850→            }
851→
852→            IniFile ini = new IniFile(newConfigPath);
853→
854→            strPassWord = ReadString(ini, "System", "PassWord");
855→            strTitle = ReadString(ini, "System", "Title");
