863→            alpha = ReadDouble(ini, "Etc", "alpha");
864→
865→            Volt.GraphMin = ReadInt(ini, "Volt", "graphMin");
866→            Volt.GraphMax = ReadInt(ini, "Volt", "graphMax");
867→
868→            Amp.GraphMin = ReadInt(ini, "Amp", "graphMin");
869→            Amp.GraphMax = ReadInt(ini, "Amp", "graphMax");
870→
871→            Flow.GraphMin = ReadInt(ini, "Flow", "graphMin");
872→            Flow.GraphMax = ReadInt(ini, "Flow", "graphMax");
873→
874→            HoldOption = ReadString(ini, "System", "HoldOption");
