**라인 2614-2690: StartPlcThread() 메서드 전체**
```csharp
private void StartPlcThread()
{
    if (GlobalValues.signalSource != "MELSEC PLC") return;

    _plc = new MelsecHelper(_actPlc);
    if (_plc.Connect())
    {
        Logger.Log("[PLC] 연결 성공! PLC 통신 스레드 시작");

        // PLC 입력 데이터 읽기 타이머
        _plcTimer = new System.Windows.Forms.Timer();
        _plcTimer.Interval = 200;  // 200ms 주기
        _plcTimer.Tick += PlcTimer_Tick;
        _plcTimer.Start();

        // PLC 출력 토글 타이머 (상태 확인용)
        _plcToggleTimer = new System.Windows.Forms.Timer();
        _plcToggleTimer.Interval = 500;  // 0.5초
        _plcToggleTimer.Tick += PlcToggleTimer_Tick;
        _plcToggleTimer.Start();
    }
    else
    {
        Logger.Log($"PLC 연결 실패: {_plc.LastError}");
    }
}

private void StopPlcThread()
{
    if (_plcToggleTimer != null)
    {
        _plcToggleTimer.Stop();
        _plcToggleTimer.Dispose();
        _plcToggleTimer = null;
    }

    if (_plcTimer != null)
    {
        _plcTimer.Stop();
        _plcTimer.Dispose();
        _plcTimer = null;
    }

    // 모든 펄스 타이머 정리
    foreach (var timer in _plcPulseTimers.Values)
    {
        timer?.Stop();
        timer?.Dispose();
    }
    _plcPulseTimers.Clear();

    if (_plc != null)
    {
        _plc.Dispose();
        _plc = null;
    }
}
```

**라인 2711-2830: PlcTimer_Tick() 메서드 전체**
```csharp
private void PlcTimer_Tick(object sender, EventArgs e)
{
    try
    {
        if (_plc == null)
            return;

        if (!_plc.IsConnected)
        {
            // PLC 재접속 시도 (1초마다)
            int now = Environment.TickCount;
            if (now - _lastPlcReconnectAttempt > 1000)  // 1초 간격
            {
                _lastPlcReconnectAttempt = now;
                Logger.Log($"[PLC] 재접속 시도 (실패 횟수: {_plcFailCount})");
                if (_plc.Connect())
                {
                    Logger.Log("[PLC] 재접속 성공");
                    _plcFailCount = 0;
                }
                else
                {
                    _plcFailCount++;
                }
            }
            return;
        }

        // [입력 블록] 읽기
        var inBlocks = MelsecHelper.ParseBlocks(GlobalValues.plcInputBlocks ?? "");
        foreach (var block in inBlocks)
        {
            var data = _plc.ReadMultipleBlocks(new List<MelsecHelper.PlcBlock> { block });

            lock (_plcInputLock)
            {
                _plcInputData = data;
            }
        }

        // ProcessScanCompleteSignals(): 입력 블록 4~7번째 워드 → 출력 블록 4~7번째 워드로 미러링
        // (JIG/Weld/Complete 신호 이후 추가 데이터 처리)
        try
        {
            ProcessScanCompleteSignals();
        }
        catch (Exception ex)
        {
            Logger.Error($"[PLC] ProcessScanCompleteSignals 예외: {ex.Message}");
        }

        _plcFailCount = 0;  // 읽기 성공 시 실패 카운터 리셋
    }
    catch (Exception ex)
    {
        Logger.Error($"[PLC] PlcTimer_Tick 예외: {ex.Message}");
        _plcFailCount++;
    }
}
```

**라인 2672-2709: PlcToggleTimer_Tick() 메서드 전체**
```csharp
private void PlcToggleTimer_Tick(object sender, EventArgs e)
{
    try
    {
        if (_plc == null || !_plc.IsConnected)
            return;

        if (GlobalValues.plcOutputBlocks == null || GlobalValues.plcOutputBlocks.Length == 0)
            return;

        var outBlocks = MelsecHelper.ParseBlocks(GlobalValues.plcOutputBlocks ?? "");
        if (outBlocks.Count == 0 || outBlocks[0].Count < 2)
            return;  // 2워드 이상일 때만 토글

        _plcToggleState = !_plcToggleState;
        WritePlcOutput(1, _plcToggleState ? 1 : 0);
    }
    catch (Exception ex)
    {
        Logger.Error($"[PLC] PlcToggleTimer_Tick 예외: {ex.Message}");
    }
}
