private bool CheckPlcJigCondition(string plcJigNo)
{
    if (string.IsNullOrWhiteSpace(plcJigNo))
        return false;

    string[] parts = plcJigNo.Split(':');
    if (parts.Length != 2 || !int.TryParse(parts[0], out int address) || !int.TryParse(parts[1], out int value))
        return false;

    int actualValue = GetPlcValue(address);
