**라인 3031-3040: SendPlcPulse() 메서드 전체**
```csharp
/// <summary>
/// 완료 신호 응답용 1초 펄스 출력 (환경설정 plcCompletePulseAddress 번지)
/// </summary>
private void SendPlcPulse(int address, int durationMs)
{
    SendPlcPulse(GlobalValues.plcCompletePulseAddress, 1000);

    if (_plc == null || !_plc.IsConnected) return;

    // 타이머 중복 생성 방지
    if (_plcPulseTimers.ContainsKey(address))
        return;

    // 즉시 ON
    _plc.WriteD(address, 1);

    // 타이머로 지정 시간 후 OFF
    var timer = new System.Windows.Forms.Timer();
    timer.Interval = durationMs;
    timer.Tick += (s, e) =>
    {
        _plc?.WriteD(address, 0);
        timer.Stop();
        timer.Dispose();
        _plcPulseTimers.Remove(address);
    };
    _plcPulseTimers[address] = timer;
    timer.Start();
}
```

